tests:
def test_initial_version_zero():
    r = Runner({})
    assert r.current_version() == 0

def test_apply_single():
    state = {}
    r = Runner(state)
    r.register(Migration(1, 'init', lambda s: s.update({'a': 1}), lambda s: s.pop('a', None)))
    r.migrate_to(1)
    assert r.current_version() == 1
    assert state == {'a': 1}
